(window.webpackJsonp=window.webpackJsonp||[]).push([[18],{645:function(n,t){n.exports="\x3c!-- \ntitle: 01-CSharp入门\nsort: \n--\x3e \n\n# CSharp入门\n\n## 安装\n\n> 安装`.NET Core`\n>\n> 验证安装：`dotnet`\n>\n> `.NET Core` 是CLR(Common Language Runtime)与FCL(Framework Class Library)\n\n## 第一个C#程序\n\n```powershell\n# 生成第一个程序\ndotnet new console --name FirstCSharp\n# 运行\ndotnet build\ndotnet run\n```\n\n```c#\n// 不使用using System.Console.WriteLine()\nusing System;\t// 引用命名空间\n\nnamespace FirstCSharp\t// 声明类的命名空间\n{\n    class Program\t\t// 声明类\n    {\n        static void Main(string[] args)\t\t// 声明静态无返回值方法\n        {\n            Console.WriteLine(TempConvert(100));   // 调用方法\n        }\n        static double TempConvert(double F)\t\t// 声明静态无返回值方法\n        {\n            double C = (F - 32) / 1.8;     // 将表达式运行结果存放在本地变量中\n            return C;\n        }\n    }\n}\n```\n\n## Dotnet\n\n```powershell\ndotnet restore\t\t# 恢复引用的库\ndotnet build\t\t# 把.cs编译成Assembly(.dll)\ndotnet .\\bin\\Debug\\netcoreapp3.1\\FirstCSharp.dll\t# 运行生成的dll\n```\n\n\n\n"}}]);